            // convention by disabling auto-generation and setting ids manually.
            b.Property(e => e.Id)
                .ToJsonProperty("id")
                .HasValueGenerationStrategy(CosmosValueGenerationStrategy.None);

            // Breaking change 3: HasIndex() was silently ignored before but now
            // throws at model build time. Removed — Cosmos DB manages indexes
            // through its own indexing policy.
        });
    }
}
